QueryScript.Source:
import sailpoint.object.*;

//log.error("event value--"+value);

queryOptions.addFilter(Filter.eq("action",context.getObjectById(IdentityTrigger.class,value).getName()));
queryOptions.addFilter(Filter.ge("created",arguments.get("fromDate")));
queryOptions.addFilter(Filter.le("created",arguments.get("toDate")));

if(arguments.get("department")!=null)
{

Filter filter1 = Filter.eq("department",arguments.get("department"));
QueryOptions qo = new QueryOptions();
qo.add(filter1);
Iterator itr = context.search(Identity.class,qo,"name");
List idList = new ArrayList();
while(itr.hasNext())
{

idList.add(itr.next()[0]);

}
queryOptions.addFilter(Filter.in("target",idList));

log.error("idList==="+idList);
}

// log.error(" queryOptions==="+queryOptions);
return queryOptions;

RenderScript.Source:
import sailpoint.object.*;
import sailpoint.api.*;

Identity identity=context.getObjectByName(Identity.class,value);

if(identity!=null)

log.error("--department in identity--"+identity.getAttribute("department"));
return identity.getAttribute("department");
return "";
